const aws = @import("aws");

const ScoringComponentResiliencyScore = @import("scoring_component_resiliency_score.zig").ScoringComponentResiliencyScore;

/// The overall resiliency score, returned as an object that includes the
/// disruption score and
/// outage score.
pub const ResiliencyScore = struct {
    /// The score generated by Resilience Hub for the scoring component after
    /// running an
    /// assessment.
    ///
    /// For example, if the `score` is 25 points, it indicates the overall score of
    /// your application generated by Resilience Hub after running an assessment.
    component_score: ?[]const aws.map.MapEntry(ScoringComponentResiliencyScore) = null,

    /// The disruption score for a valid key.
    disruption_score: []const aws.map.MapEntry(f64),

    /// The outage score for a valid key.
    score: f64 = 0,

    pub const json_field_names = .{
        .component_score = "componentScore",
        .disruption_score = "disruptionScore",
        .score = "score",
    };
};
